"use client"

import { useEffect, useState } from "react"

export default function TemplatePage({ params }: any) {
  const [data, setData] = useState<any>({})
  const [docs, setDocs] = useState<any[]>([])
  const propertyId = "698250b3eacd04e2ddcd61c4"

  useEffect(() => {
    fetch(`/api/templates/${params.id}/values?propertyId=${propertyId}`)
      .then(res => res.json())
      .then(setData)

    fetch(`/api/documents?propertyId=${propertyId}&templateId=${params.id}`)
      .then(res => res.json())
      .then(setDocs)
  }, [])

  const save = async () => {
    await fetch("/api/deal-data", {
      method: "POST",
      body: JSON.stringify({ propertyId, data }),
    })
    alert("Saved")
  }

  const generate = async () => {
    const res = await fetch("/api/documents/generate", {
      method: "POST",
      body: JSON.stringify({
        templateId: params.id,
        propertyId,
      }),
    })

    const result = await res.json()

    alert("Generated")
    window.open(result.file)
  }

  return (
    <div className="p-6">

      <h1 className="text-xl font-bold mb-4">Template</h1>

      {/* VARIABLES */}
      {Object.keys(data).map(key => (
        <div key={key} className="mb-2">
          <label>{key}</label>
          <input
            value={data[key] || ""}
            onChange={(e) =>
              setData({ ...data, [key]: e.target.value })
            }
            className="border px-2 ml-2"
          />
        </div>
      ))}

      {/* ACTIONS */}
      <div className="mt-4 flex gap-3">
        <button onClick={save} className="bg-blue-500 text-white px-4 py-2">
          Save
        </button>

        <button onClick={generate} className="bg-green-500 text-white px-4 py-2">
          Generate Document
        </button>
      </div>

      {/* DOCUMENT LIST */}
      <div className="mt-6">
        <h2 className="font-bold">Generated Documents</h2>

        {docs.map(doc => (
          <div key={doc._id}>
            <a href={doc.fileUrl} target="_blank">
              Version {doc.version}
            </a>
          </div>
        ))}
      </div>

    </div>
  )
}